Python<pre><code>class ProjectAPI(PermissionViewSetMixin, APIViewSet):
    model = Project

    async def has_permission(self, request, operation):
        user = request.auth
        if user is None:
            return False
        if operation == "create":
            return user.can_create_projects
        return True

    async def has_object_permission(self, request, operation, obj):
        user = request.auth
        if operation in ("update", "delete"):
            return obj.owner_id == user.id or user.is_admin
        return True

    def get_permission_queryset(self, request, queryset):
        user = request.auth
        if user.is_admin:
            return queryset
        return queryset.filter(
            Q(owner=user) | Q(members=user)
        ).distinct()
